@using sv_a734ca4092e442f3ab6da45efc1f8d39.Components.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

@if (isLoading && result is null)
{
    <div class="d-flex justify-content-center py-5">
        <div class="spinner-border text-primary" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-link" @onclick="RetryLoad">Retry</button>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-3">
            <CatalogSidebar Categories="categories"
                            OnFilterApplied="HandleFilterApplied"
                            OnFilterCleared="HandleFilterCleared" />
        </div>
        <div class="col-md-9">
            @if (result is not null)
            {
                <CatalogToolbar SortBy="@sortBy"
                                StartItem="startItem"
                                EndItem="endItem"
                                TotalCount="result.TotalCount"
                                OnSortChanged="HandleSortChanged" />

                @if (result.Items.Count == 0)
                {
                    <div class="text-center py-5 text-muted">
                        <h4>No products found</h4>
                        <p>Try adjusting your filters or search criteria.</p>
                    </div>
                }
                else
                {
                    @if (isLoading)
                    {
                        <div class="text-center py-2">
                            <div class="spinner-border spinner-border-sm text-primary" role="status">
                                <span class="visually-hidden">Loading...</span>
                            </div>
                        </div>
                    }

                    <ProductGrid Products="result.Items"
                                 OnProductSelected="HandleProductSelected"
                                 OnAddToCart="HandleAddToCart" />

                    @if (totalPages > 1)
                    {
                        <div class="mt-4">
                            <CatalogPagination CurrentPage="currentPage"
                                               TotalPages="totalPages"
                                               OnPageChanged="HandlePageChanged" />
                        </div>
                    }
                }
            }
        </div>
    </div>
}

@code {
    private List<string> categories = [];
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;
    private PagedResult<Product>? result;
    private bool isLoading;
    private string? errorMessage;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private int totalPages => result is null or { TotalCount: 0 }
        ? 1
        : (int)Math.Ceiling((double)result.TotalCount / PageSize);

    private int startItem => result is null or { TotalCount: 0 }
        ? 0
        : (result.Page - 1) * result.PageSize + 1;

    private int endItem => result is null
        ? 0
        : Math.Min(result.Page * result.PageSize, result.TotalCount);

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            categories = await categoriesTask;
            result = await searchTask;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task SearchProductsAsync()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            result = await ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task HandleFilterCleared()
    {
        currentFilter = new ProductFilter(null, null, null, false);
        currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await SearchProductsAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for cart integration
        return Task.CompletedTask;
    }

    private async Task RetryLoad()
    {
        await LoadDataAsync();
    }
}
